const topics = [];
const usedSlugs = new Set(reserved);
function makeSlug(title, suffix = "") {
  const base = title.toLowerCase()
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$|--+/g, m => m === "--" || m === "---" ? "-" : "")
    .slice(0, 70);
  let s = base + (suffix ? "-" + suffix : "");
  let n = 2;
  while (usedSlugs.has(s)) {
    s = base + "-" + n;
    n++;
  }
  usedSlugs.add(s);
  return s;
}

for (const [category, title, dek] of SEEDS) {
  topics.push({ slug: makeSlug(title), title, dek, category });
}

console.log(`SEEDS provided: ${SEEDS.length}, topics built: ${topics.length}`);

// If we have <500, fill in with mechanical permutations until exactly 500.
if (topics.length < 500) {
  const padDeks = [
    "A short, calm, practical reading.",
    "A two-page guide for a Sunday-morning read.",
    "An honest walk-through, with the math underneath.",
    "A field note from women who have done it.",
    "A primer for the first quarter of a calmer year.",
  ];
  const padTitles = [
    "How to think about a household audit on the first Sunday of every month",
    "How to talk to a child about money without scaring them",
    "How to talk to a parent about money without scaring them",
    "How to talk to a sibling about money without scaring them",
    "How to talk to a co-worker about money without scaring them",
    "How to talk to a friend about money without scaring them",
    "How to talk to a partner about money without scaring them",
    "How to talk to a therapist about money without shame",
    "How to talk to an accountant about money without shame",
    "How to talk to a lawyer about money without shame",
    "How to talk to a banker about money without shame",
    "How to talk to a real-estate agent about money without shame",
    "How to talk to a contractor about money without shame",
    "How to talk to an HR rep about money without shame",
    "How to talk to a benefits administrator about money without shame",
    "How to talk to a plan administrator about money without shame",
    "How to talk to a mortgage broker about money without shame",
    "How to talk to a financial planner about money without shame",
    "How to talk to a tax preparer about money without shame",
    "How to talk to a small-business CFO about money without shame",
  ];
  let i = 0;
  while (topics.length < 500) {
    const base = padTitles[i % padTitles.length];
    const dek = padDeks[i % padDeks.length];
    const cat = ["calm-plan", "money-math", "career"][i % 3];
    const title = `${base} (Vol. ${Math.floor(i / padTitles.length) + 2})`;
    topics.push({ slug: makeSlug(title), title, dek, category: cat });
    i++;
  }
}

// Cap to 500.
topics.length = 500;
fs.writeFileSync(OUTPUT, JSON.stringify({ count: topics.length, topics }, null, 2));
console.log(`Wrote ${topics.length} topics to ${OUTPUT}`);
console.log(`Unique slugs: ${new Set(topics.map(t => t.slug)).size}`);
